  healthy: boolean;
  costRank: number;
}

export class ProviderRegistry {
  private readonly providers = new Map<string, Provider>();

  register(provider: Provider): void {
    this.providers.set(provider.id, provider);
  }

  list(): Provider[] {
    return Array.from(this.providers.values());
  }

  findByCapability(capability: string): Provider[] {
    return this.list().filter((provider) => provider.healthy && provider.capabilities.includes(capability));
  }
}

import { ProviderSelector } from './ProviderSelector';

export interface RoutingDecision {
  capability: string;
  providerId?: string;
  route: 'direct' | 'fallback';
}

export class ToolRouter {
  constructor(private readonly selector: ProviderSelector) {}

  route(capability: string): RoutingDecision {
    const provider = this.selector.select(capability);
    if (provider) {
      return { capability, providerId: provider.id, route: 'direct' };
    }

    return { capability, route: 'fallback' };
  }
}

import { Provider, ProviderRegistry } from './ProviderRegistry';

export class ProviderSelector {
  constructor(private readonly registry: ProviderRegistry) {}

  select(capability: string): Provider | undefined {
    const candidates = this.registry.findByCapability(capability);
    return candidates.sort((left, right) => left.costRank - right.costRank)[0];
  }
}

