export type AutoManagerState = 'idle' | 'planning' | 'executing' | 'testing' | 'publishing' | 'done';

export class AutoManager {
  private state: AutoManagerState = 'idle';
  private activePlan?: ArchitectPlan;

  constructor(
    readonly architect: AutoArchitect,
    readonly programmer: AutoProgrammer,
    readonly designer: AutoDesigner,
    readonly artist: AutoArtist,
    readonly tester: AutoTester,
    readonly optimizer: AutoOptimizer,
    readonly publisher: AutoPublisher,
  ) {}

  async plan(description: string, modules: string[]): Promise<ArchitectPlan> {
    this.state = 'planning';
    this.activePlan = this.architect.plan(description, modules);
    return this.activePlan;
  }

  async execute(): Promise<void> {
    if (!this.activePlan) throw new Error('No active plan — call plan() first');
    this.state = 'executing';
    await this.architect.implement(this.activePlan);
  }

  async test(): Promise<void> {
    this.state = 'testing';
    await this.tester.run();
  }

  complete(): void {
    this.state = 'done';
    this.activePlan = undefined;
  }

  getState(): AutoManagerState {
    return this.state;
  }
}

import { AssetMetrics } from '../assetFactory/AssetMetrics';
import { ResourceManager } from '../runtime/ResourceManager';

export interface OptimizationReport {
  id: string;
  recommendations: string[];
  appliedAt: string;
}

export class AutoOptimizer {
  constructor(
    private readonly metrics: AssetMetrics,
    private readonly resources: ResourceManager,
  ) {}

  analyze(): string[] {
    const recommendations: string[] = [];
    const usage = this.resources.getUsage();
    const quota = this.resources.getQuota();

    if (usage.memoryMb > quota.maxMemoryMb * 0.8) {
      recommendations.push('Memory usage is above 80% — consider evicting asset cache');
    }
    if (usage.cpuPercent > quota.maxCpuPercent * 0.9) {
      recommendations.push('CPU usage is above 90% — reduce concurrent job concurrency');
    }

    const summary = this.metrics.summary();
    for (const metric of summary) {
      if (metric.total > 0 && metric.failed / metric.total > 0.1) {
        recommendations.push(`High failure rate for "${metric.category}" (${(metric.failed / metric.total * 100).toFixed(0)}%) — investigate generator`);
      }
    }

    return recommendations;
  }

  optimize(): OptimizationReport {
    return {
      id: `opt-${Date.now()}-${Math.random().toString(36).slice(2)}`,
      recommendations: this.analyze(),
      appliedAt: new Date().toISOString(),
    };
  }
}

import { Bootstrap } from './Bootstrap';
import { Lifecycle } from './Lifecycle';
