import { ModuleLoader } from './ModuleLoader';
import { Logger } from './Logger';
import { HealthMonitor } from './HealthMonitor';
import { ShutdownManager } from './ShutdownManager';
import { CommandBus } from './CommandBus';
import { QueryBus } from './QueryBus';
import { StateManager } from './StateManager';
import { ExtensionHost } from './ExtensionHost';
import { Telemetry } from './Telemetry';

export class Kernel {
  readonly lifecycle = new Lifecycle();
  readonly container = new ServiceContainer();
  readonly eventBus = new EventBus();
  readonly scheduler = new Scheduler();
  readonly config = new Configuration();
  readonly moduleLoader = new ModuleLoader();
  readonly logger = new Logger();
  readonly health = new HealthMonitor();
  readonly shutdown = new ShutdownManager();
  readonly commandBus = new CommandBus();
  readonly queryBus = new QueryBus();
  readonly state = new StateManager();
  readonly extensions = new ExtensionHost();
  readonly telemetry = new Telemetry();
  readonly bootstrap = new Bootstrap();

  private running = false;

  async start(configOverrides?: Record<string, unknown>): Promise<void> {
    try {
      this.lifecycle.transition('initializing');
      this.logger.info('[Kernel] Loading configuration');
      if (configOverrides) this.config.load(configOverrides);

      this.lifecycle.transition('starting');
      this.logger.info('[Kernel] Registering core services');
      this._registerCoreServices();

      this.logger.info('[Kernel] Initialising bootstrap modules');
      await this.bootstrap.start();

      this.logger.info('[Kernel] Registering shutdown hooks');
      this._registerShutdownHooks();

      this.logger.info('[Kernel] Starting scheduler');
      this.scheduler.startAll();

      this.lifecycle.transition('running');
      this.running = true;
      this.logger.info('[Kernel] Running');
      this.telemetry.track('kernel.started');
    } catch (err) {
      this.lifecycle.transition('error');
      this.logger.error('[Kernel] Startup failed', err);
      throw err;
    }
  }

  async stop(): Promise<void> {
    if (!this.running) return;
    this.lifecycle.transition('stopping');
    this.logger.info('[Kernel] Shutting down');
    this.scheduler.stopAll();
    await this.extensions.deactivateAll();
    await this.shutdown.shutdown();
    this.lifecycle.transition('stopped');
    this.running = false;
    this.logger.info('[Kernel] Stopped');
    this.telemetry.track('kernel.stopped');
  }

  isRunning(): boolean { return this.running; }

  private _registerCoreServices(): void {
    this.container.registerInstance('eventBus', this.eventBus);
    this.container.registerInstance('scheduler', this.scheduler);
    this.container.registerInstance('config', this.config);
    this.container.registerInstance('moduleLoader', this.moduleLoader);
    this.container.registerInstance('logger', this.logger);
    this.container.registerInstance('health', this.health);
    this.container.registerInstance('commandBus', this.commandBus);
    this.container.registerInstance('queryBus', this.queryBus);
    this.container.registerInstance('state', this.state);
    this.container.registerInstance('extensions', this.extensions);
    this.container.registerInstance('telemetry', this.telemetry);
  }

  private _registerShutdownHooks(): void {
    this.shutdown.register('scheduler', async () => this.scheduler.stopAll());
    this.shutdown.register('extensions', async () => { await this.extensions.deactivateAll(); });
    this.shutdown.register('telemetry', async () => { this.telemetry.flush(); });
    this.shutdown.register('logger', async () => { this.logger.info('[Kernel] Shutdown complete'); });
  }
}

export type JobStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled';

export interface ScheduledJob {
  id: string;
  name: string;
  intervalMs?: number;
  runOnce?: boolean;
  execute: () => Promise<void>;
}

interface JobState {
  job: ScheduledJob;
  status: JobStatus;
  lastRun?: Date;
  handle?: ReturnType<typeof setInterval>;
}

export class Scheduler {
  private readonly jobs = new Map<string, JobState>();

  register(job: ScheduledJob): void {
    if (this.jobs.has(job.id)) throw new Error(`Job already registered: ${job.id}`);
    this.jobs.set(job.id, { job, status: 'pending' });
  }

  start(id: string): void {
    const state = this.require(id);
    if (state.status === 'running') return;
    state.status = 'running';
    const run = async () => {
      state.lastRun = new Date();
      try {
        await state.job.execute();
        if (state.job.runOnce) { state.status = 'completed'; this.stop(id); }
      } catch { state.status = 'failed'; this.stop(id); }
    };
    if (state.job.intervalMs !== undefined) {
      state.handle = setInterval(run, state.job.intervalMs);
    }
    void run();
  }

  startAll(): void {
    for (const id of this.jobs.keys()) this.start(id);
  }

  stop(id: string): void {
    const state = this.require(id);
    if (state.handle !== undefined) { clearInterval(state.handle); state.handle = undefined; }
    if (state.status === 'running') state.status = 'cancelled';
  }

  stopAll(): void {
    for (const id of this.jobs.keys()) this.stop(id);
  }

  async runOnce(id: string): Promise<void> {
    const state = this.require(id);
    state.lastRun = new Date();
    try {
      await state.job.execute();
      state.status = 'completed';
    } catch (e) {
      state.status = 'failed';
      throw e;
    }
  }

  getStatus(id: string): JobStatus { return this.require(id).status; }

  list(): { id: string; name: string; status: JobStatus; lastRun?: Date }[] {
    return [...this.jobs.values()].map(s => ({
      id: s.job.id,
      name: s.job.name,
      status: s.status,
      lastRun: s.lastRun,
    }));
  }

  private require(id: string): JobState {
    const s = this.jobs.get(id);
    if (!s) throw new Error(`Job not found: ${id}`);
    return s;
  }
}

export interface Extension {
  readonly extensionId: string;
  readonly name: string;
  activate(api: ExtensionHostAPI): Promise<void>;
  deactivate?(): Promise<void>;
}

export interface ExtensionHostAPI {
  readonly extensionId: string;
  log(message: string): void;
}

export interface LoadedExtension {
  extensionId: string;
  name: string;
  active: boolean;
  activatedAt?: string;
}

export class ExtensionHost {
  private readonly extensions = new Map<string, { ext: Extension; state: LoadedExtension }>();

  register(extension: Extension): void {
    if (this.extensions.has(extension.extensionId)) throw new Error(`Extension already registered: ${extension.extensionId}`);
    this.extensions.set(extension.extensionId, {
      ext: extension,
      state: { extensionId: extension.extensionId, name: extension.name, active: false },
    });
  }

  async activate(extensionId: string): Promise<void> {
    const entry = this.require(extensionId);
    if (entry.state.active) return;
    const api: ExtensionHostAPI = {
      extensionId,
      log: (msg) => console.log(`[ext:${extensionId}] ${msg}`),
    };
    await entry.ext.activate(api);
    entry.state.active = true;
    entry.state.activatedAt = new Date().toISOString();
  }

  async deactivate(extensionId: string): Promise<void> {
    const entry = this.require(extensionId);
    if (!entry.state.active) return;
    await entry.ext.deactivate?.();
    entry.state.active = false;
  }

  async activateAll(): Promise<void> {
    for (const id of this.extensions.keys()) await this.activate(id);
  }

  async deactivateAll(): Promise<void> {
    for (const id of [...this.extensions.keys()].reverse()) await this.deactivate(id);
  }

  get(extensionId: string): LoadedExtension | undefined { return this.extensions.get(extensionId)?.state; }
  list(): LoadedExtension[] { return [...this.extensions.values()].map(e => ({ ...e.state })); }

  private require(id: string) {
    const e = this.extensions.get(id);
    if (!e) throw new Error(`Extension not found: ${id}`);
    return e;
  }
}
